1	export type Cell = [number, number];
2	
3	function cellEquals(a: Cell, b: Cell): boolean {
4	  return a[0] === b[0] && a[1] === b[1];
5	}
6	
7	function isNeighbor(a: Cell, b: Cell): boolean {
8	  const rowDistance = Math.abs(a[0] - b[0]);
9	  const colDistance = Math.abs(a[1] - b[1]);
10	  const isWithinOneStep = rowDistance <= 1 && colDistance <= 1;
11	  return !cellEquals(a, b) && isWithinOneStep;
12	}
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const countNeighbors = (cell: Cell): number =>
16	    liveCells.filter((other) => isNeighbor(other, cell)).length;
17	
18	  const isLive = (cell: Cell): boolean =>
19	    liveCells.some((other) => cellEquals(other, cell));
20	
21	  const survivors = liveCells.filter((cell) => {
22	    const neighbors = countNeighbors(cell);
23	    return neighbors === 2 || neighbors === 3;
24	  });
25	
26	  const births: Cell[] = [];
27	  for (const cell of liveCells) {
28	    for (let dRow = -1; dRow <= 1; dRow++) {
29	      for (let dCol = -1; dCol <= 1; dCol++) {
30	        const candidate: Cell = [cell[0] + dRow, cell[1] + dCol];
31	        const alreadyCounted = births.some((b) => cellEquals(b, candidate));
32	        if (
33	          !isLive(candidate) &&
34	          !alreadyCounted &&
35	          countNeighbors(candidate) === 3
36	        ) {
37	          births.push(candidate);
38	        }
39	      }
40	    }
41	  }
42	
43	  return [...survivors, ...births];
44	}
