it("should keep a block still life unchanged", () => {
  const block: Cell[] = [[0, 0], [0, 1], [1, 0], [1, 1]];
  const result = nextGeneration(block);
  expect(result).toHaveLength(4);
  for (const cell of block) {
    expect(result).toContainEqual(cell);
  }
});
